module multi_pipe_4bit(
    input clk,
    input rst_n,
    input [3:0] mul_a,
    input [3:0] mul_b,
    output reg [7:0] mul_out,
    input [3:0] a,
    input [3:0] b,
    output [7:0] out
);
parameter size = 4;
reg [3:0] reg_a, reg_b;
reg [7:0] reg_out, out;
reg [7:0] add_out;
reg [7:0] reg_s1 [size-1:0];
reg [7:0] reg_s2 [size-1:0];
reg [7:0] reg_s3 [size-1:0];
reg [7:0] reg_s4 [size-1:0];
reg [7:0] reg_s5 [size-1:0];
reg [7:0] reg_s6 [size-1:0];
always @(*) begin
    reg_a = {{size{1'b0}}, mul_a};
    reg_b = {{size{1'b0}}, mul_b};
end
genvar i;
generate
    for (i = 0; i < size; i = i + 1) begin : mul_block
        always @(*) begin
            if (reg_b[i] == 1'b1) begin
                reg_s1[i] = reg_a << i;
            end
            else begin
                reg_s1[i] = 'd0;
            end
        end
    end
endgenerate
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        reg_out <= 'd0;
    end
    else begin
        for (int i = 0; i < size; i = i + 1) begin
            if (i == 0) begin
                reg_out <= reg_s1[i];
            end
            else begin
                reg_out <= reg_out + reg_s1[i];
            end
        end
    end
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_out <= 'd0;
    end
    else begin
        mul_out <= reg_out;
    end
end
endmodule
